import{_ as a,o as i,c as t,ag as l}from"./chunks/framework.brm5GKsQ.js";const m=JSON.parse('{"title":"v1.0 Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"guide/v1-roadmap.md","filePath":"guide/v1-roadmap.md"}'),o={name:"guide/v1-roadmap.md"};function r(n,e,s,c,d,u){return i(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="v1-0-roadmap" tabindex="-1">v1.0 Roadmap <a class="header-anchor" href="#v1-0-roadmap" aria-label="Permalink to &quot;v1.0 Roadmap&quot;">​</a></h1><p>Current version: <strong>0.2.0</strong></p><h2 id="what-1-0-means" tabindex="-1">What 1.0 Means <a class="header-anchor" href="#what-1-0-means" aria-label="Permalink to &quot;What 1.0 Means&quot;">​</a></h2><p>A 1.0 release signals: the public API is stable, the layout algorithm is correct, performance claims are verified, and the package is published on npm for external adoption. After 1.0, breaking changes require a major version bump.</p><h2 id="release-criteria" tabindex="-1">Release Criteria <a class="header-anchor" href="#release-criteria" aria-label="Permalink to &quot;Release Criteria&quot;">​</a></h2><h3 id="correctness" tabindex="-1">Correctness <a class="header-anchor" href="#correctness" aria-label="Permalink to &quot;Correctness&quot;">​</a></h3><ul><li>[x] All Yoga compatibility tests pass (41/41)</li><li>[x] Re-layout fuzz tests pass (1200+)</li><li>[x] Mutation testing validates fuzz suite catches known cache mutations</li><li>[x] All feature tests pass (~110)</li><li>[x] Total test count: 1368 passing</li><li>[ ] No known layout correctness bugs</li><li>[x] Intentional Yoga divergences documented</li></ul><h3 id="api-stability" tabindex="-1">API Stability <a class="header-anchor" href="#api-stability" aria-label="Permalink to &quot;API Stability&quot;">​</a></h3><ul><li>[x] Yoga-compatible API surface (same constants, same method names)</li><li>[x] Two entry points: <code>flexture</code> (zero-alloc) and <code>flexture/classic</code> (allocating)</li><li>[ ] API surface audit</li><li>[ ] TypeScript declaration files build cleanly</li><li>[ ] No planned breaking changes</li></ul><h3 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><ul><li>[x] Benchmark suite exists</li><li>[x] Performance claims documented</li><li>[ ] Benchmark numbers verified and recorded in release notes</li><li>[x] Bundle size measured and documented</li></ul><h3 id="packaging" tabindex="-1">Packaging <a class="header-anchor" href="#packaging" aria-label="Permalink to &quot;Packaging&quot;">​</a></h3><ul><li>[x] <code>package.json</code> has <code>engines</code> field</li><li>[x] <code>package.json</code> has correct <code>exports</code> map</li><li>[x] <code>files</code> field limits published content</li><li>[ ] Published on npm as <code>flexture</code></li><li>[x] MIT license</li></ul><h3 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><ul><li>[x] README with usage, performance, and API overview</li><li>[x] API reference</li><li>[x] Performance benchmarks and methodology</li><li>[x] Test infrastructure and methodology</li><li>[x] Algorithm explanation</li><li>[x] Yoga comparison</li><li>[ ] CHANGELOG.md</li></ul><h2 id="what-s-not-in-1-0" tabindex="-1">What&#39;s NOT in 1.0 <a class="header-anchor" href="#what-s-not-in-1-0" aria-label="Permalink to &quot;What&#39;s NOT in 1.0&quot;">​</a></h2><ul><li><strong>CSS Grid</strong> -- Flexture is a flexbox engine</li><li><strong>Text layout</strong> -- Consumers handle text measurement via measure functions</li><li><strong>Multi-thread / worker support</strong> -- Synchronous by design</li><li><strong>Browser build</strong> -- Targets Node.js/Bun (ESM works in browsers but not a gate)</li></ul>',17)])])}const p=a(o,[["render",r]]);export{m as __pageData,p as default};
